  <script>
    const coinHero = document.getElementById('coin-hero');
    let scene, camera, renderer, coinGroup;
    let clock = new THREE.Clock();
    let isPaused = false;

    function initThree() {
      scene = new THREE.Scene();
      camera = new THREE.PerspectiveCamera(45, window.innerWidth/window.innerHeight, 0.1, 100);
      camera.position.z = 3;
      renderer = new THREE.WebGLRenderer({ canvas: coinHero, antialias: true });
      renderer.setSize(window.innerWidth, window.innerHeight * 0.6);
      renderer.setPixelRatio(window.devicePixelRatio);

      // Lighting
      const light1 = new THREE.DirectionalLight(0xffffff, 1);
      light1.position.set(5, 5, 5);
      scene.add(light1);
      const light2 = new THREE.DirectionalLight(0xffffff, 0.8);
      light2.position.set(-5, -3, 5);
      scene.add(light2);

      // Coin geometry
      createCoin();
    }

    function createCoin() {
      coinGroup = new THREE.Group();

      // Reeded edge (cylinder)
      const cylinderGeo = new THREE.CylinderGeometry(0.9, 0.9, 0.1, 32);
      const cylinderMat = new THREE.MeshStandardMaterial({ 
        color: 0x888888,
        metalness: 0.7,
        roughness: 0.4
      });
      const cylinder = new THREE.Mesh(cylinderGeo, cylinderMat);
      coinGroup.add(cylinder);

      // Front face (emblem)
      const frontCanvas = document.createElement('canvas');
      frontCanvas.width = 256; frontCanvas.height = 256;
      const fctx = frontCanvas.getContext('2d');
      drawEmblem(fctx, 'WASTEDTOKEN MINT', '#ffffff', '#333333');
      const frontTexture = new THREE.CanvasTexture(frontCanvas);
      const frontMat = new THREE.MeshStandardMaterial({ 
        map: frontTexture,
        metalness: 0.6,
        roughness: 0.5
      });
      const frontGeo = new THREE.CircleGeometry(0.9, 32);
      const frontFace = new THREE.Mesh(frontGeo, frontMat);
      coinGroup.add(frontFace);

      // Back face (token count)
      const backCanvas = document.createElement('canvas');
      backCanvas.width = 256; backCanvas.height = 256;
      const bctx = backCanvas.getContext('2d');
      drawTokenText(bctx, '10,000 TOKENS', '#ffffff', '#333333');
      const backTexture = new THREE.CanvasTexture(backCanvas);
      const backMat = new THREE.MeshStandardMaterial({ 
        map: backTexture,
        metalness: 0.6,
        roughness: 0.5
      });
      const backGeo = new THREE.CircleGeometry(0.9, 32);
      const backFace = new THREE.Mesh(backGeo, backMat);
      backFace.rotation.x = Math.PI;
      coinGroup.add(backFace);

      scene.add(coinGroup);
    }

    function drawEmblem(ctx, text, color, bgColor) {
      ctx.fillStyle = bgColor;
      ctx.fillRect(0, 0, 256, 256);
      ctx.font = 'bold 80px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = color;
      ctx.fillText(text, 128, 128);
    }

    function drawTokenText(ctx, text, color, bgColor) {
      ctx.fillStyle = bgColor;
      ctx.fillRect(0, 0, 256, 256);
      ctx.font = 'bold 40px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = color;
      ctx.fillText(text, 128, 128);
    }

    function animate() {
      if (!isPaused) {
        const t = clock.getElapsedTime();
        const loopT = (t % 4) / 4; // 4 seconds per full loop
        renderCoin(loopT);
        renderer.render(scene, camera);
        requestAnimationFrame(animate);
      }
    }

    function renderCoin(t) {
      if (!coinGroup) return;
      const angleY = Math.PI * 2 * t;
      const angleX = Math.PI * t;
      coinGroup.rotation.y = angleY;
      coinGroup.rotation.x = angleX;
    }

    window.demo = {
      canvas: coinHero,
      setTime(t) {
        if (coinGroup) renderCoin(t);
      },
      pause() {
        isPaused = true;
      }
    };

    initThree();
    animate();

    // Edition canvases
    document.querySelectorAll('.edition-canvas').forEach((canvas, idx) => {
      const ctx = canvas.getContext('2d');
      let color, gradient;
      switch (idx) {
        case 0: // Bronze
          gradient = ctx.createRadialGradient(90, 90, 50, 90, 90, 180);
          gradient.addColorStop(0, '#b87333');
          gradient.addColorStop(1, '#6e4413');
          break;
        case 1: // Silver
          gradient = ctx.createRadialGradient(90, 90, 50, 90, 90, 180);
          gradient.addColorStop(0, '#cccccc');
          gradient.addColorStop(1, '#4d4d4d');
          break;
        case 2: // Gold
          gradient = ctx.createRadialGradient(90, 90, 50, 90, 90, 180);
          gradient.addColorStop(0, '#ffd700');
          gradient.addColorStop(1, '#b8860b');
          break;
        case 3: // Black
          gradient = ctx.createRadialGradient(90, 90, 50, 90, 90, 180);
          gradient.addColorStop(0, '#2e2e2e');
          gradient.addColorStop(1, '#0a0a0a');
          break;
      }
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, 180, 180);

      // Reeds
      for (let i = 0; i < 32; i++) {
        const angle = (i / 32) * Math.PI * 2;
        const x = 90 + Math.cos(angle) * 85;
        const y = 90 + Math.sin(angle) * 85;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(90 + Math.cos(angle) * 75, 90 + Math.sin(angle) * 75);
        ctx.strokeStyle = '#444';
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      // Token text
      const texts = ['10K', '10K', '10K', '10K'];
      ctx.fillStyle = idx === 3 ? '#666' : '#fff';
      ctx.font = 'bold 40px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(texts[idx], 90, 120);
    });
  </script>
</body>
