    }
    .editions {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
      gap: 30px;
      padding: 40px;
    }
    .edition {
      background-color: #222;
      border-radius: 16px;
      overflow: hidden;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: space-between;
      position: relative;
      padding-bottom: 30px;
    }
    .edition-canvas {
      width: 100%;
      aspect-ratio: 1 / 1;
      background-color: #2e2e2e;
    }
    .buy {
      margin-top: auto;
      padding: 14px 28px;
      font-size: 16px;
      color: white;
      background-color: gold;
      border: none;
      cursor: pointer;
      border-radius: 8px;
      transition: background 0.3s;
    }
    .buy:hover {
      background-color: #ffcc4d;
    }
    .sold-out-overlay, .coming-soon-overlay {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      font-size: 24px;
      font-weight: bold;
      background-color: rgba(0,0,0,0.7);
      padding: 16px 32px;
      border-radius: 8px;
    }
    .coming-soon-overlay {
      color: #00ffcc;
    }
  </style>
</head>
<body>
  <canvas id="coin-hero"></canvas>

  <section class="about">
    <h2>About WastedToken Mint</h2>
    <p>WastedToken Mint crafts premium collectible challenge coins, each embodying the spirit of digital scarcity and physical artistry. Our limited editions are designed for discerning collectors who value both innovation and tradition.</p>
  </section>

  <section class="editions">
    <!-- Editions will be inserted here by JavaScript -->
  </section>

  <script>
    const canvas = document.getElementById('coin-hero');
    const ctx = canvas.getContext('2d');
    let t = 0;
    let isAnimating = true;

    function renderCoin(t) {
      const width = canvas.width;
      const height = canvas.height;
      const cx = width / 2;
      const cy = height / 2;
      const radius = Math.min(width, height) * 0.4;

      ctx.clearRect(0, 0, width, height);

      // Calculate rotation angles
      const theta = 2 * Math.PI * t; // Y-axis spin
      const phi = Math.sin(2 * Math.PI * (t + 0.5)) * Math.PI / 4; // X-axis tilt

      // Determine face visibility
      const showFront = phi >= 0;

      // Light direction based on rotation
      const lightX = Math.cos(theta);
      const lightY = -Math.sin(phi);

      // Draw reeds (concentric circles)
      ctx.save();
      for (let i = 1; i <= 20; i++) {
        const r = radius * (i / 20);
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.1 + 0.05 * i})`;
        ctx.stroke();
      }

      // Metallic shading with moving highlight
      const gradient = ctx.createRadialGradient(
        cx - radius * lightX * 0.3,
        cy - radius * lightY * 0.3,
        radius * 0.2,
        cx + radius * lightX * 0.1,
        cy + radius * lightY * 0.1,
        radius
      );
      gradient.addColorStop(0, '#fff');
      gradient.addColorStop(1, '#888');

      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(cx, cy, radius, 0, Math.PI * 2);
      ctx.fill();

      // Draw face content
      if (showFront) {
        drawEmblem(ctx, cx, cy, radius);
      } else {
        drawDenomination(ctx, cx, cy, radius);
      }
      ctx.restore();
    }

    function drawEmblem(ctx, cx, cy, radius) {
      ctx.save();
      ctx.translate(cx, cy);
      ctx.scale(0.5, 0.5);
      ctx.fillStyle = 'gold';
      ctx.beginPath();
      ctx.arc(0, 0, radius * 2, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = '#333';
      ctx.lineWidth = 10;
      ctx.stroke();
      ctx.restore();
    }

    function drawDenomination(ctx, cx, cy, radius) {
      ctx.fillStyle = 'white';
      ctx.font = `${radius / 4}px Arial`;
      ctx.textAlign = 'center';
      ctx.fillText('10,000 TOKENS', cx, cy + radius * 0.3);
    }

    function animate() {
      if (isAnimating) {
        requestAnimationFrame(animate);
        t += 0.01;
        renderCoin(t % 1);
      }
    }

    window.demo = {
      canvas,
      setTime: renderCoin,
      pause: () => { isAnimating = false; }
    };

    animate();

    // Editions grid
    const editionsData = [
      { edition: 'bronze', state: 'available' },
      { edition: 'silver', state: 'available' },
      { edition: 'gold', state: 'sold-out' },
      { edition: 'black', state: 'coming-soon' }
    ];

    function renderEditionCanvas(ctx, cx, cy, radius, color) {
      // Reeds
      for (let i = 1; i <= 20; i++) {
        const r = radius * (i / 20);
        ctx.beginPath();
        ctx.arc(cx, cy, r, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(255, 255, 255, ${0.1 + 0.05 * i})`;
        ctx.stroke();
      }

      // Metallic shading
      const gradient = ctx.createRadialGradient(
        cx - radius * 0.3,
        cy - radius * 0.3,
        radius * 0.2,
        cx + radius * 0.1,
        cy + radius * 0.1,
        radius
      );
      gradient.addColorStop(0, '#fff');
      gradient.addColorStop(1, color);
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(cx, cy, radius, 0, Math.PI * 2);
      ctx.fill();

      // Front face emblem
      drawEmblem(ctx, cx, cy, radius);
    }

    const editionsContainer = document.querySelector('.editions');
    editionsData.forEach(data => {
      const editionDiv = document.createElement('div');
      editionDiv.className = 'edition';
      editionDiv.setAttribute('data-edition', data.edition);
      editionDiv.setAttribute('data-state', data.state);

      const canvasEl = document.createElement('canvas');
      canvasEl.className = 'edition-canvas';

      if (data.state === 'available') {
        const button = document.createElement('button');
        button.className = 'buy';
        button.textContent = 'Add to cart';
        editionDiv.appendChild(button);
      } else if (data.state === 'sold-out') {
        const overlay = document.createElement('div');
        overlay.className = 'sold-out-overlay';
        overlay.textContent = 'SOLD OUT';
        editionDiv.appendChild(overlay);
      } else if (data.state === 'coming-soon') {
        const overlay = document.createElement('div');
        overlay.className = 'coming-soon-overlay';
        overlay.textContent = 'Minting Spring 2024';
        editionDiv.appendChild(overlay);
      }

      // Render canvas
      const ctxCanvas = canvasEl.getContext('2d');
      const width = canvasEl.width;
      const height = canvasEl.height;
      const cx = width / 2;
      const cy = height / 2;
      const radius = Math.min(width, height) * 0.4;

      let color;
      switch (data.edition) {
        case 'bronze': color = '#b87333'; break;
        case 'silver': color = '#cccccc'; break;
        case 'gold': color = '#ffd700'; break;
        case 'black': color = '#1a1a1a'; break;
      }

      renderEditionCanvas(ctxCanvas, cx, cy, radius, color);

      editionDiv.appendChild(canvasEl);
      editionsContainer.appendChild(editionDiv);
    });
  </script>
</body>
</html>
